import { NextRequest, NextResponse } from 'next/server'

function slugifyHeading(text: string): string {
  return text
    .toLowerCase()
    .trim()
    .replace(/^(\d+)\./, '$1')
    .replace(/[^a-z0-9\s-]/g, '')
    .replace(/\s+/g, '-')
}

function buildTocFromHeadings(md: string): string {
  const lines = md.split('\n')
  const toc: string[] = []

  for (const line of lines) {
    if (!line.startsWith('## ')) continue
    const heading = line.slice(3).trim()
    if (/^table of contents$/i.test(heading)) continue

    const m = heading.match(/^(\d+)\.\s+(.*)$/)
    if (!m) continue

    const num = m[1]
    const title = m[2]
    const slug = slugifyHeading(heading)
    toc.push(`${num}. [${title}](#${slug})`)
  }

  return toc.join('\n')
}

function ensureFreshTableOfContents(md: string): string {
  // Replace any existing "## Table of Contents ... ---" block with an auto-generated TOC.
  // If none exists, leave the markdown untouched.
  const toc = buildTocFromHeadings(md)
  if (!toc) return md

  const re = /## Table of Contents\n[\s\S]*?\n---\n\n/m
  if (!re.test(md)) return md

  return md.replace(re, `## Table of Contents\n${toc}\n\n---\n\n`)
}

const GUIDES: Record<string, string> = {
  'supports-planner': "# CaseSync Guide \u2014 Supports Planner\n**Beatrice Loving Heart (BLH)**\n*Your complete guide to using the CaseSync case management portal*\n\n---\n\n## Table of Contents\n1. [Getting Started](#1-getting-started)\n2. [Your Dashboard](#2-your-dashboard)\n3. [Calendar](#7-calendar)\n4. [Chat](#8-chat)\n5. [BLH Bot](#9-blh-bot)\n6. [Mobile App](#10-mobile-app)\n7. [Quick Reference](#11-quick-reference)\n\n---\n\n## 1. Getting Started\n\n### Receiving Your Invitation\n\nYour Team Manager or Supervisor will send you an invitation email from CaseSync. This email will come from a BLH-related address and will contain a secure sign-up link.\n\n1. Open the invitation email in your inbox.\n2. Click the **\"Accept Invitation\"** or **\"Set Up Your Account\"** link.\n3. The link will open CaseSync in your browser and prompt you to create a password.\n\n> \ud83d\udca1 **Tip:** Check your spam or junk folder if you don't see the email within a few minutes.\n\n### Setting Your Password\n\n1. On the password setup screen, enter a password that is:\n   - At least 8 characters long\n   - Contains at least one uppercase letter\n   - Contains at least one number or symbol\n2. Confirm your password by typing it again.\n3. Click **Save Password**.\n\n> \ud83d\udca1 **Tip:** Use a password manager to generate and store a strong password. Never share your CaseSync password with anyone, including your Team Manager.\n\n### Logging In\n\n1. Go to your organization's CaseSync URL (provided by your Team Manager).\n2. Enter your email address.\n3. Enter your password.\n4. Click **Sign In**.\n\nIf you forget your password, click **\"Forgot password?\"** on the login page and follow the reset instructions sent to your email.\n\n### First-Time Onboarding\n\nWhen you first log in, you may see a short onboarding checklist or guided tour. This will walk you through:\n- Confirming your full name and contact information\n- Understanding your role and permissions\n- Taking a quick guided tour of the portal\n\nComplete these steps before diving into your work \u2014 they only take a few minutes and will help you get oriented.\n\n---\n\n## 2. Your Dashboard\n\nThe Dashboard is your home base. Every time you log in, you'll land here.\n\n### What You See\n\n| Element | What It Does |\n|---|---|\n| **Greeting** | Shows your name and today's date |\n| **Alert Banner** | Highlights clients that need immediate attention |\n| **Week Strip** | Shows deadlines in the next 7 days |\n| **Client Cards** | Each card = one of your clients |\n| **Search Bar** | Find a client by name |\n| **Filter Bar** | Narrow your view by status, flag, or deadline type |\n| **Sort** | Change the order of client cards |\n\n### Understanding the Alert Banner\n\nThe orange/red banner at the top of the Dashboard is your urgency signal. It appears when:\n- A client has a **missed Monthly Monitoring** submission\n- A **deadline is overdue** (past the due date)\n- A **service authorization is expiring** soon\n- Your Team Manager has **flagged a client** for your attention\n\nClick on any alert to jump directly to that client.\n\n### Understanding the Week Strip\n\nThe week strip shows a 7-day timeline starting from today. Each deadline chip shows:\n- The client's initials or name\n- The type of deadline (SPM, Contact Log, etc.)\n- A color: \ud83d\udd34 Red = overdue | \ud83d\udfe1 Amber = due within 3 days | \ud83d\udfe2 Green = on track\n\n### Using Search, Filter & Sort\n\n- **Search**: Start typing a client's first or last name in the search box. Results update instantly.\n- **Filter**: Click the filter icon to narrow results. You can filter by:\n  - Compliance status (on track, at risk, overdue)\n  - Service type\n  - Alert flag\n- **Sort**: Change the sort order to view clients by:\n  - Name (A\u2013Z)\n  - Next deadline (soonest first)\n  - Risk level (highest first)\n\n---\n\n## 3. Calendar\n\n### Accessing the Calendar\n\nClick **Calendar** in the top navigation bar (desktop) or the calendar icon in the bottom navigation (mobile).\n\n### Navigating Views\n\n| View | Best For |\n|---|---|\n| **Month** | Planning ahead, spotting busy weeks |\n| **Week** | Day-by-day breakdown of your schedule |\n| **Day** | Detailed view of a single day |\n\nClick the **< >** arrows to move forward or backward in time.\n\n### What Appears on Your Calendar\n- SPM due dates for each client\n- Contact log reminders\n- Service authorization expiration dates\n- Any deadlines set by your Team Manager\n\n### Using the Calendar for Planning\n\n1. At the start of each week, open the Week view to see what's due.\n2. At the start of each month, check the Month view \u2014 look for any \"red zone\" days near the 15th.\n3. Click any deadline chip to jump directly to that client profile.\n\n---\n\n## 4. Chat\n\n### Accessing Chat\n\nClick **Chat** in the top navigation bar or bottom navigation on mobile.\n\n### Direct Messages (DMs)\n\n- Send a private message to your Team Manager, a colleague, or any CaseSync user at your organization.\n- Click **+ New Message** and search for the person's name.\n- Messages are private and only visible to you and the recipient.\n\n### Team Channels\n\n- Your Team Manager may set up channels for your team.\n- These are group conversations \u2014 everyone in the channel can see the messages.\n- Good for: team announcements, shared questions, non-client-specific coordination.\n\n### Client Threads\n\n- Some discussions are attached to a specific client.\n- These threads appear in the client's profile under the **Discussion** tab.\n- Use these to coordinate with your Team Manager about a specific person.\n\n### Chat Etiquette\n\n- Keep Chat professional \u2014 it's an official BLH communication channel.\n- Do not share full client names, Medicaid IDs, or other identifiers in chat messages.\n- Use the client profile, not chat, for official documentation.\n- Respond to your Team Manager's messages promptly \u2014 within one business day.\n\n---\n\n## 5. BLH Bot\n\nBLH Bot is your AI assistant, available 24/7 inside CaseSync.\n\n### How to Open BLH Bot\n\nClick the **purple button** \ud83d\udfe3 in the bottom-right corner of any page.\n\n### What You Can Ask\n\n| Question Type | Example |\n|---|---|\n| Deadlines | \"What's due this week?\" |\n| Procedures | \"How do I log a home visit?\" |\n| Client info | \"What services is [client name] enrolled in?\" |\n| Eligibility codes | \"What does CLS mean?\" |\n| Policy | \"When is the SPM due?\" |\n| Navigation | \"Where do I upload documents?\" |\n\n### Tips for Better Answers\n\n- Be specific: \"How do I edit a client's date of birth?\" gets a better answer than \"How do I edit?\"\n- You can follow up: after an answer, ask \"Can you explain that more?\" or \"What if I get an error?\"\n- BLH Bot has BLH-wide CaseSync visibility \u2014 you can ask about your own caseload, team activity, planner coverage, and org-wide operational questions.\n\n> \u26a0\ufe0f **Note:** BLH Bot provides guidance and information based on CaseSync features and BLH policies. For clinical decisions, always use your professional judgment and consult with your supervisor if in doubt.\n\n---\n\n## 6. Mobile App\n\n### Installing CaseSync on Your Phone\n\nCaseSync is a Progressive Web App (PWA) \u2014 you can install it on your phone's home screen without an app store.\n\n**On iPhone (Safari):**\n1. Open CaseSync in the Safari browser.\n2. Tap the **Share** button (the square with an arrow at the bottom of the screen).\n3. Scroll down and tap **\"Add to Home Screen.\"**\n4. Give it a name (or keep \"CaseSync\") and tap **Add**.\n\n**On Android (Chrome):**\n1. Open CaseSync in the Chrome browser.\n2. Tap the **three-dot menu** (\u22ee) in the top-right corner.\n3. Tap **\"Add to Home Screen\"** or **\"Install App.\"**\n4. Tap **Install** to confirm.\n\nThe CaseSync icon will appear on your home screen. Tap it to launch the app in full-screen mode.\n\n### Mobile Navigation\n\nOn mobile, the navigation bar moves to the **bottom of the screen** for easy one-thumb access. You'll find shortcuts to:\n- Dashboard\n- Chat\n- Calendar\n- Settings\n\n### Mobile Tips\n\n- The mobile layout is fully optimized \u2014 all features work on your phone.\n- Turn on browser notifications for CaseSync so you receive deadline alerts even when the app is closed.\n- The mobile app works best on a modern smartphone (iPhone 12+ or Android 2021+).\n\n---\n\n## 7. Quick Reference\n\n### Keyboard Shortcuts (Desktop)\n\n| Shortcut | Action |\n|---|---|\n| `/` | Focus the search bar |\n| `Esc` | Close a modal or cancel editing |\n| `Ctrl+S` / `Cmd+S` | Save (in edit mode) |\n| `?` | Open keyboard shortcuts help |\n\n### Key Dates to Remember\n\n| Date | What's Due |\n|---|---|\n| 15th of each month | Monthly Monitoring (SPM) for all clients |\n| Ongoing | Log contact within 24 hours of interaction |\n| 30 days before expiry | Service authorization renewal initiated |\n\n### Common Issues & Solutions\n\n| Problem | Solution |\n|---|---|\n| Can't log in | Check email/password. Use \"Forgot password?\" to reset. |\n| Client not showing on dashboard | Check filters \u2014 clear all filters and search again |\n| Upload failing | Check file size (max 25MB) and file type |\n| Page not loading | Refresh the browser. Try incognito mode. |\n| Something looks broken | Open BLH Bot and describe the issue, or contact your Team Manager |\n\n### Getting Help\n\n1. **BLH Bot** \u2014 your first stop for any question\n2. **Chat** \u2014 message your Team Manager directly\n3. **Your Team Manager** \u2014 for anything that needs a human answer\n4. **Supervisor** \u2014 for escalated issues or policy questions\n\n---\n\n*CaseSync is built for Beatrice Loving Heart (BLH). For technical issues, contact your Team Manager or Supervisor.*\n*Guide version: 2025 | Role: Supports Planner*\n",
  'team-manager': "# CaseSync Guide \u2014 Team Manager\n**Beatrice Loving Heart (BLH)**\n*Your complete guide to using the CaseSync case management portal*\n\n---\n\n## Table of Contents\n1. [Getting Started](#1-getting-started)\n2. [Your Dashboard](#2-your-dashboard)\n3. [Working with Clients](#3-working-with-clients)\n4. [Logging Contact](#4-logging-contact)\n5. [Monthly Monitoring (SPM)](#5-monthly-monitoring-spm)\n6. [Documents](#6-documents)\n7. [Calendar](#7-calendar)\n8. [Chat](#8-chat)\n9. [BLH Bot](#9-blh-bot)\n10. [Mobile App](#10-mobile-app)\n11. [Team Dashboard](#11-team-dashboard)\n12. [Assigning Clients to Planners](#12-assigning-clients-to-planners)\n13. [Monitoring Your Team's Compliance](#13-monitoring-your-teams-compliance)\n14. [Using BLH Bot for Team Questions](#14-using-blh-bot-for-team-questions)\n15. [Quick Reference](#15-quick-reference)\n\n---\n\n## 1. Getting Started\n\n### Receiving Your Invitation\n\nYour Supervisor will send you an invitation email from CaseSync. This email contains a secure sign-up link.\n\n1. Open the invitation email in your inbox.\n2. Click the **\"Accept Invitation\"** or **\"Set Up Your Account\"** link.\n3. The link will open CaseSync in your browser and prompt you to create a password.\n\n> \ud83d\udca1 **Tip:** Check your spam or junk folder if you don't see the email within a few minutes.\n\n### Setting Your Password\n\n1. On the password setup screen, enter a password that is:\n   - At least 8 characters long\n   - Contains at least one uppercase letter\n   - Contains at least one number or symbol\n2. Confirm your password by typing it again.\n3. Click **Save Password**.\n\n> \ud83d\udca1 **Tip:** Use a password manager to generate and store a strong password. Never share your CaseSync password with anyone, including your Supervisor.\n\n### Logging In\n\n1. Go to your organization's CaseSync URL.\n2. Enter your email address.\n3. Enter your password.\n4. Click **Sign In**.\n\nIf you forget your password, click **\"Forgot password?\"** on the login page.\n\n### Your Role and Permissions\n\nAs a Team Manager, you can:\n- View and edit all clients assigned to your team\n- View all contact logs and SPMs submitted by your planners\n- Assign and reassign clients to planners on your team\n- View your team's compliance dashboard\n- Communicate with your planners via Chat\n- Use BLH Bot for team-level questions\n\nYou cannot:\n- Access client records for teams you don't manage (unless granted by a Supervisor)\n- Invite new users to the system (Supervisor only)\n- Change user roles (Supervisor only)\n- Access the Supervisor Dashboard or Admin Panel\n\n---\n\n## 2. Your Dashboard\n\nThe Dashboard is your personal home base \u2014 it shows *your* assigned clients and upcoming deadlines. The Team Dashboard (Section 11) shows your team's activity.\n\n### What You See\n\n| Element | What It Does |\n|---|---|\n| **Greeting** | Shows your name and today's date |\n| **Alert Banner** | Highlights clients needing immediate attention |\n| **Week Strip** | Shows deadlines in the next 7 days |\n| **Client Cards** | Each card = one of your clients (if you carry a caseload) |\n| **Search Bar** | Find a client by name |\n| **Filter Bar** | Narrow by status, flag, or deadline type |\n| **Sort** | Change order of client cards |\n\n### Understanding the Alert Banner\n\nThe orange/red banner appears when:\n- A client has a **missed Monthly Monitoring** submission\n- A **deadline is overdue**\n- A **service authorization is expiring** soon\n- You've flagged a client for follow-up\n\nClick any alert to go directly to that client.\n\n### Understanding the Week Strip\n\nThe week strip shows a 7-day timeline. Each deadline chip shows:\n- Client initials or name\n- Deadline type (SPM, Contact Log, etc.)\n- Color: \ud83d\udd34 Red = overdue | \ud83d\udfe1 Amber = due within 3 days | \ud83d\udfe2 Green = on track\n\n---\n\n## 3. Calendar\n\n### Accessing the Calendar\n\nClick **Calendar** in the top navigation.\n\n### Views\n\n- **Month** \u2014 planning ahead, spotting busy weeks\n- **Week** \u2014 day-by-day breakdown\n- **Day** \u2014 detailed single-day view\n\n### What Appears on Your Calendar\n\n- Your personal deadlines (if you carry clients)\n- Team-wide SPM deadlines (visible on the Team Dashboard calendar)\n\n---\n\n## 4. Chat\n\n### Direct Messages\n\n- Send private messages to your planners, colleagues, or Supervisor.\n- Click **+ New Message**, search for the person, and start typing.\n\n### Team Channels\n\n- Use your team channel to make announcements, share reminders, or coordinate.\n- All planners on your team should be in the team channel.\n\n### Client Threads\n\n- Discuss specific clients in threads attached to their profile.\n- These keep client discussions organized and auditable.\n\n### Chat Best Practices for Team Managers\n\n- Post deadline reminders (e.g., \"SPMs due in 5 days \u2014 let me know if you need help\")\n- Use DMs for private feedback to planners\n- Avoid discussing sensitive client information in group channels\n- Respond to planner messages within one business day\n\n---\n\n## 5. BLH Bot\n\nBLH Bot is your AI assistant, available anytime via the purple button \ud83d\udfe3 in the bottom-right corner.\n\n### What Team Managers Can Ask\n\n| Question | Example |\n|---|---|\n| Team status | \"Which of my planners have overdue SPMs?\" |\n| Client lookup | \"What are the deadlines for [client name]?\" |\n| Policy | \"What's the SPM submission deadline?\" |\n| Procedures | \"How do I reassign a client to a different planner?\" |\n| Help | \"How do I export a report?\" |\n\n---\n\n## 6. Mobile App\n\n### Installing CaseSync on Your Phone\n\n**On iPhone (Safari):**\n1. Open CaseSync in Safari.\n2. Tap the **Share** button \u2192 **\"Add to Home Screen\"** \u2192 **Add**.\n\n**On Android (Chrome):**\n1. Open CaseSync in Chrome.\n2. Tap **\u22ee** \u2192 **\"Add to Home Screen\"** or **\"Install App\"** \u2192 **Install**.\n\nThe CaseSync icon will appear on your home screen and launch in full-screen mode.\n\n---\n\n## 7. Team Dashboard\n\nThe Team Dashboard is your overview of your entire team's activity and compliance.\n\n### Accessing the Team Dashboard\n\nClick **Team** in the top navigation bar.\n\n### What You See\n\n| Section | What It Shows |\n|---|---|\n| **Planner Overview** | List of all your Supports Planners |\n| **Client Count** | How many clients each planner manages |\n| **SPM Compliance** | % of SPMs submitted on time per planner |\n| **Overdue Flags** | Number of overdue deadlines per planner |\n| **Last Active** | When each planner last logged in |\n\n### Compliance Stats\n\nThe compliance column shows a color-coded status for each planner:\n- \ud83d\udfe2 **Green** \u2014 all SPMs submitted, no overdue items\n- \ud83d\udfe1 **Amber** \u2014 1\u20132 overdue items or approaching deadline\n- \ud83d\udd34 **Red** \u2014 multiple overdue items or missed SPMs\n\n> \ud83d\udca1 **Tip:** Use this view at the start of each week to quickly identify which planners may need support or a reminder.\n\n### Drilling Down\n\nClick any planner's name to see:\n- Their full client list\n- Individual compliance status per client\n- Recent contact log activity\n\n---\n\n## 8. Assigning Clients to Planners\n\n### Assigning a New Client\n\nWhen a new client is added to your team:\n1. Open the client's profile.\n2. Click **Assign Planner** (or look for the \"Assigned To\" field in the profile).\n3. Select the planner from the dropdown list.\n4. Click **Save**.\n\nThe client will now appear on the planner's Dashboard.\n\n### Reassigning a Client\n\nIf a planner leaves, takes leave, or has too many clients:\n1. Open the client's profile.\n2. Click **Edit** \u2192 change the \"Assigned To\" field.\n3. Select the new planner.\n4. Click **Save**.\n\nThe client will move from the old planner's Dashboard to the new one. All historical data (contact logs, SPMs, documents) remains attached to the client record.\n\n> \ud83d\udca1 **Tip:** Notify both the outgoing and incoming planner via Chat when making a reassignment, especially if there are active situations that require handoff notes.\n\n### Reviewing Your Team's Caseload Balance\n\nFrom the Team Dashboard, review each planner's client count. Consider reassigning if:\n- One planner has significantly more clients than others\n- A planner is consistently missing deadlines (may indicate overload)\n- A new planner joins and needs clients assigned\n\n---\n\n## 9. Monitoring Your Team's Compliance\n\n### SPM Compliance Check\n\n1. Go to the **Team Dashboard**.\n2. Sort by **SPM Compliance** (lowest first) to see who needs attention.\n3. Click on a planner to see which specific clients are missing SPMs.\n4. Send a Chat DM to the planner with a reminder.\n\n### Overdue Deadline Review\n\n1. From the Team Dashboard, click **View Overdue Items**.\n2. You'll see a list of every overdue deadline across your team, sorted by date.\n3. Click any item to go to the client profile.\n\n### Weekly Compliance Routine (Recommended)\n\n| Day | Action |\n|---|---|\n| **Monday** | Review Team Dashboard for overdue items from previous week |\n| **10th of month** | Send SPM reminder to all planners via team Chat channel |\n| **14th of month** | Final SPM reminder \u2014 check who hasn't submitted |\n| **16th of month** | Review SPM compliance report \u2014 follow up with any late submitters |\n\n### Flagging Clients That Need Attention\n\n1. Open the client's profile.\n2. Click the **Flag** icon.\n3. Add a note (e.g., \"Needs SPM review before 15th\").\n4. The assigned planner will see the flag on their Dashboard.\n\n---\n\n## 10. Using BLH Bot for Team Questions\n\nBLH Bot can help you manage your team more efficiently.\n\n### Team-Specific Questions You Can Ask\n\n- **\"Show me a summary of my team's compliance this month\"**\n- **\"Which clients on my team are overdue for SPMs?\"**\n- **\"Who is [client name] assigned to?\"**\n- **\"How do I send a bulk reminder to my planners?\"**\n- **\"What's the policy on reassigning clients mid-month?\"**\n- **\"Explain the SPM requirements for [service type]\"**\n\n### Generating a Team Summary\n\nAsk BLH Bot: \"Give me a compliance summary for my team\" \u2014 it will pull your team's current stats and highlight the most urgent items.\n\n### Getting Policy Guidance\n\nBLH Bot is trained on BLH's policies and procedures. Use it to quickly answer planner questions before escalating to your Supervisor.\n\n---\n\n## 11. Quick Reference\n\n### Keyboard Shortcuts (Desktop)\n\n| Shortcut | Action |\n|---|---|\n| `/` | Focus the search bar |\n| `Esc` | Close a modal or cancel editing |\n| `Ctrl+S` / `Cmd+S` | Save (in edit mode) |\n| `?` | Open keyboard shortcuts help |\n\n### Key Dates\n\n| Date | Action |\n|---|---|\n| 1st of month | Review prior month compliance, plan current month |\n| 10th of month | Send SPM reminder to your team |\n| 15th of month | SPM deadline \u2014 all planners must have submitted |\n| 16th of month | Review compliance, follow up with late submitters |\n\n### Common Issues & Solutions\n\n| Problem | Solution |\n|---|---|\n| Planner can't see their client | Check that client is assigned to them in the client profile |\n| SPM not showing in compliance report | Ask planner to resubmit; check that \"Submit\" was clicked (not just saved) |\n| Need to add a new user | Contact your Supervisor \u2014 only Supervisors can invite users |\n| Can't reassign a client | Ensure you have edit access; contact Supervisor if access is restricted |\n\n### Getting Help\n\n1. **BLH Bot** \u2014 first stop for any question\n2. **Chat** \u2014 message your Supervisor or a colleague\n3. **Supervisor** \u2014 for access requests, policy questions, or escalated issues\n\n---\n\n*CaseSync is built for Beatrice Loving Heart (BLH). For technical issues, contact your Supervisor.*\n*Guide version: 2025 | Role: Team Manager*\n",
  'supervisor': "# CaseSync Guide \u2014 Supervisor\n**Beatrice Loving Heart (BLH)**\n*Your complete guide to using the CaseSync case management portal*\n\n---\n\n## Table of Contents\n1. [Getting Started](#1-getting-started)\n2. [Your Dashboard](#2-your-dashboard)\n3. [Working with Clients](#3-working-with-clients)\n4. [Logging Contact](#4-logging-contact)\n5. [Monthly Monitoring (SPM)](#5-monthly-monitoring-spm)\n6. [Documents](#6-documents)\n7. [Calendar](#7-calendar)\n8. [Chat](#8-chat)\n9. [BLH Bot](#9-blh-bot)\n10. [Mobile App](#10-mobile-app)\n11. [Supervisor Dashboard](#11-supervisor-dashboard)\n12. [Admin Panel \u2014 Managing Users](#12-admin-panel--managing-users)\n13. [Audit Log \u2014 HIPAA Compliance](#13-audit-log--hipaa-compliance)\n14. [Org-Wide Reporting & CSV Export](#14-org-wide-reporting--csv-export)\n15. [Quick Reference](#15-quick-reference)\n\n---\n\n## 1. Getting Started\n\n### Account Setup\n\nAs a Supervisor, your account is either set up by another Supervisor or the system administrator. You'll receive an invitation email with a secure setup link.\n\n1. Click the **\"Set Up Your Account\"** link in the invitation email.\n2. Create a strong password (8+ characters, mixed case, numbers/symbols).\n3. Confirm your password and click **Save Password**.\n4. Complete the brief onboarding checklist.\n\n### Your Role and Permissions\n\nAs a Supervisor, you have the **highest level of access** in CaseSync:\n- View all clients across all teams\n- Access every Team Manager's team dashboard\n- Access the Supervisor Dashboard with org-wide analytics\n- Manage users via the Admin Panel (invite, change roles, deactivate)\n- View the Audit Log for HIPAA compliance\n- Export org-wide reports as CSV\n- Access all Chat channels and threads\n\n### Logging In\n\n1. Go to your organization's CaseSync URL.\n2. Enter your email address and password.\n3. Click **Sign In**.\n\n---\n\n## 2. Your Dashboard\n\nYour personal Dashboard shows clients directly assigned to you (if any) and your personal upcoming deadlines.\n\n### What You See\n\n| Element | What It Does |\n|---|---|\n| **Greeting** | Your name, role, and today's date |\n| **Alert Banner** | Org-wide or personal alerts |\n| **Week Strip** | Deadlines in the next 7 days |\n| **Client Cards** | Clients directly assigned to you |\n| **Search / Filter / Sort** | Tools to navigate your client list |\n\n> \ud83d\udca1 **Tip:** For org-wide activity, use the **Supervisor Dashboard** (Section 11). Your personal Dashboard is for your own direct responsibilities.\n\n### Navigation Links Available to Supervisors\n\nIn the top navigation bar, you'll see additional links:\n- **Dashboard** \u2014 your personal home\n- **Team** \u2014 Team Manager view\n- **Supervisor** \u2014 Supervisor Dashboard with analytics\n- **Chat** \u2014 messaging\n- **Calendar** \u2014 your calendar\n- **Admin** \u2014 user management\n- **Audit Log** \u2014 compliance record\n- **Settings** \u2014 your personal settings\n\n---\n\n## 3. Calendar\n\n### Accessing the Calendar\n\nClick **Calendar** in the top navigation.\n\nAs Supervisor, your calendar shows your personal deadlines. For team-wide deadlines, use the Supervisor Dashboard's timeline view.\n\n---\n\n## 4. Chat\n\n### Your Chat Access\n\nAs Supervisor, you can:\n- Send direct messages to any user in the organization\n- Post in any team channel\n- View any client thread (for auditing purposes)\n\n### Best Practices\n\n- Use DMs for sensitive or personal feedback to Team Managers.\n- Use team channels for broad announcements.\n- Remember: Chat messages may be reviewed in audits. Keep communications professional.\n\n---\n\n## 5. BLH Bot\n\nBLH Bot is available via the purple button \ud83d\udfe3 in the bottom-right corner of any page.\n\n### Questions Supervisors Can Ask\n\n| Question | Example |\n|---|---|\n| Org status | \"Which teams have the lowest SPM compliance?\" |\n| User lookup | \"Who is assigned to [client name]?\" |\n| Policy | \"What are the HIPAA requirements for audit logs?\" |\n| Reporting | \"How do I export a CSV of all overdue SPMs?\" |\n| Admin | \"How do I change a user's role?\" |\n| Analysis | \"What are the most common compliance issues?\" |\n\n---\n\n## 6. Mobile App\n\n### Installing CaseSync on Your Phone\n\n**On iPhone (Safari):**\n1. Open CaseSync in Safari \u2192 tap **Share** \u2192 **\"Add to Home Screen\"** \u2192 **Add**.\n\n**On Android (Chrome):**\n1. Open CaseSync in Chrome \u2192 tap **\u22ee** \u2192 **\"Install App\"** \u2192 **Install**.\n\nAll Supervisor features are available on mobile, including the Admin Panel and Supervisor Dashboard.\n\n---\n\n## 7. Supervisor Dashboard\n\nThe Supervisor Dashboard gives you a real-time, org-wide view of CaseSync activity.\n\n### Accessing the Supervisor Dashboard\n\nClick **Supervisor** in the top navigation bar.\n\n### Overview Panels\n\n| Panel | What It Shows |\n|---|---|\n| **Total Clients** | Active client count across the org |\n| **Active Planners** | Number of active Supports Planners |\n| **SPM Compliance Rate** | % of SPMs submitted on time (this month) |\n| **Overdue Items** | Total overdue deadlines across all teams |\n\n### Charts & Analytics\n\n**Compliance by Team**\n- Bar chart showing SPM compliance % for each team.\n- Click a bar to drill into that team's details.\n\n**Compliance Trend**\n- Line chart showing compliance rates over the past 6 months.\n- Identify whether compliance is improving or declining.\n\n**Deadline Heatmap**\n- A calendar-style heatmap showing deadline density by day.\n- Dark squares = many deadlines that day; light squares = few.\n- Use this to anticipate high-pressure periods and plan support accordingly.\n\n**Risk Scores**\n- Each client has an automated risk score based on:\n  - Overdue SPMs\n  - Missed contact logs\n  - Expiring service authorizations\n  - Days since last contact\n- Higher scores = higher risk of compliance failure or service disruption.\n- Sort the client list by risk score to prioritize your review.\n\n### Team-by-Team Drill-Down\n\n1. From the Supervisor Dashboard, find the **Teams** section.\n2. Click any Team Manager's name to see:\n   - Their planners and client assignments\n   - Individual planner compliance stats\n   - Flagged clients within their team\n3. Use this to have informed conversations with Team Managers about their team's performance.\n\n### Org-Wide Client List\n\nThe Supervisor Dashboard includes a filterable list of all clients in the system:\n- Filter by team, planner, risk score, compliance status, or service type\n- Click any client to open their profile\n- Sort by next deadline, risk score, or last activity\n\n---\n\n## 8. Admin Panel \u2014 Managing Users\n\nThe Admin Panel is your tool for managing who has access to CaseSync.\n\n### Accessing the Admin Panel\n\nClick **Admin** in the top navigation bar.\n\n### Inviting a New User\n\n1. In the Admin Panel, click **+ Invite User**.\n2. Enter the new user's:\n   - Full name\n   - Email address\n   - Role (Supports Planner, Team Manager, or Supervisor)\n   - Team assignment (for planners and team managers)\n3. Click **Send Invitation**.\n\nThe user will receive an email with a secure link to set up their account. The link expires after 48 hours \u2014 resend if needed.\n\n> \ud83d\udca1 **Tip:** Always confirm the user's email address before sending the invitation. Invitations sent to the wrong address can create security issues.\n\n### Changing a User's Role\n\n1. In the Admin Panel, find the user in the **Users** list.\n2. Click their name to open their user profile.\n3. Click **Edit Role**.\n4. Select the new role from the dropdown.\n5. Click **Save**.\n\nThe change takes effect immediately \u2014 the user's navigation and permissions will update on their next page load.\n\n> \u26a0\ufe0f **Important:** Changing a user's role can affect their access to client records. Review the implications before making a change:\n> - Demoting a Team Manager to Planner removes their team dashboard access\n> - Promoting a Planner to Team Manager grants access to their assigned team's data\n> - Granting Supervisor access gives full org-wide access \u2014 use carefully\n\n### Deactivating a User\n\nWhen a staff member leaves BLH:\n1. In the Admin Panel, find the user.\n2. Click their name \u2192 click **Deactivate Account**.\n3. Confirm the deactivation.\n\nDeactivated users cannot log in, but their historical data (contact logs, SPMs, audit trail) is preserved.\n\n> \u26a0\ufe0f **Before deactivating:** Reassign their clients to an active planner to avoid orphaned records.\n\n### Resetting a User's Password\n\nIf a user is locked out:\n1. In the Admin Panel, find the user.\n2. Click **Send Password Reset** \u2192 confirm.\n\nThe user will receive a reset email. They must complete the reset within 2 hours.\n\n### Managing Team Assignments\n\n1. In the Admin Panel, find the user.\n2. Click **Edit Team Assignment**.\n3. Select the correct team from the dropdown.\n4. Click **Save**.\n\n---\n\n## 9. Audit Log \u2014 HIPAA Compliance\n\nThe Audit Log records every significant action taken in CaseSync. It is your primary tool for HIPAA compliance review and incident investigation.\n\n### Accessing the Audit Log\n\nClick **Audit Log** in the top navigation bar.\n\n### What the Audit Log Records\n\nEvery entry in the Audit Log includes:\n- **Timestamp** \u2014 exact date and time of the action (UTC)\n- **User** \u2014 who performed the action\n- **Action** \u2014 what was done (e.g., \"Viewed client profile,\" \"Updated contact log,\" \"Exported report\")\n- **Resource** \u2014 what was affected (client ID, document name, etc.)\n- **IP Address** \u2014 where the action originated\n\n### Types of Actions Logged\n\n| Category | Examples |\n|---|---|\n| **Authentication** | Login, logout, failed login attempt, password reset |\n| **Client Records** | Viewed profile, edited field, deleted entry |\n| **Contact Logs** | Created, edited, deleted contact log entry |\n| **SPMs** | Submitted, edited, deleted SPM |\n| **Documents** | Uploaded, downloaded, deleted document |\n| **Admin Actions** | Invited user, changed role, deactivated account |\n| **Exports** | Downloaded CSV report |\n| **Chat** | (Message content is not logged, but session activity is) |\n\n### Filtering the Audit Log\n\nUse the filter options to narrow results:\n- **Date range** \u2014 search within specific dates\n- **User** \u2014 see all actions by a specific person\n- **Action type** \u2014 filter by category (e.g., only \"Client Records\")\n- **Client** \u2014 see all actions related to a specific client\n\n### Investigating an Incident\n\nIf you need to investigate a potential HIPAA incident (unauthorized access, accidental disclosure):\n1. Open the Audit Log.\n2. Filter by the date of the incident.\n3. Search for the client or user involved.\n4. Review the list of actions \u2014 look for unusual access patterns (e.g., a user accessing many records quickly, or accessing records outside their caseload).\n5. Export the relevant log entries as CSV for your records.\n\n### Exporting the Audit Log\n\n1. Apply your filters.\n2. Click **Export to CSV**.\n3. The file will download to your computer.\n\n> \u26a0\ufe0f **Reminder:** Audit log exports contain sensitive data. Store them securely and in compliance with BLH's data retention policy. Do not share audit logs via email without encryption.\n\n### HIPAA Minimum Necessary Standard\n\nWhen reviewing audit logs, remember the HIPAA Minimum Necessary rule: users should only access the client records necessary for their job. If you see a Supports Planner regularly accessing records outside their assigned caseload, investigate and document your findings.\n\n---\n\n## 10. Org-Wide Reporting & CSV Export\n\nCaseSync includes reporting tools to help you monitor compliance, prepare for audits, and make data-driven staffing decisions.\n\n### Accessing Reports\n\nFrom the **Supervisor Dashboard**, click the **Reports** tab.\n\n### Available Report Types\n\n| Report | Description |\n|---|---|\n| **SPM Compliance Report** | All SPMs submitted (or not) by month, team, and planner |\n| **Overdue Deadlines Report** | All overdue items across the org, with planner and team |\n| **Client Risk Report** | All clients ranked by risk score |\n| **Contact Log Activity** | Contact log volume by planner and time period |\n| **Service Authorization Expiry** | Clients with authorizations expiring in the next 30/60/90 days |\n| **User Activity Report** | Login frequency and last-active dates per user |\n\n### Generating a Report\n\n1. In the Reports tab, select the report type.\n2. Set your filters:\n   - **Date range** \u2014 required for most reports\n   - **Team** \u2014 leave blank for org-wide, or select a specific team\n   - **Planner** \u2014 optional, for individual-level reports\n3. Click **Generate Report**.\n4. The report will render on-screen with interactive charts and a data table.\n\n### Exporting to CSV\n\n1. After generating a report, click **Export to CSV**.\n2. The file will download to your computer.\n3. Open in Excel or Google Sheets for further analysis or formatting.\n\n> \ud83d\udca1 **Tip:** For state agency reporting, generate the SPM Compliance Report and Service Authorization Expiry report on the 16th of each month. This gives you a clean picture of the prior month's activity plus upcoming renewals.\n\n### Scheduling Reports (if available)\n\nSome reports can be scheduled for automatic delivery:\n1. Generate the report.\n2. Click **Schedule This Report**.\n3. Choose frequency (monthly, weekly) and delivery time.\n4. The report will be saved to your Supervisor Dashboard automatically.\n\n### Using Reports for Supervision\n\n| Report | Use It To... |\n|---|---|\n| SPM Compliance | Identify which teams and planners need follow-up |\n| Overdue Deadlines | Prioritize your supervisory calls this week |\n| Client Risk | Find high-risk clients for quality review visits |\n| Service Auth Expiry | Proactively manage renewals before services lapse |\n| User Activity | Identify inactive users who may have left the org |\n\n---\n\n## 11. Quick Reference\n\n### Navigation Summary\n\n| Page | Who Has Access | Purpose |\n|---|---|---|\n| Dashboard | All users | Personal client list and deadlines |\n| Team | TM, Supervisor | Team planner stats and assignment |\n| Supervisor | Supervisor only | Org-wide analytics and risk |\n| Admin | Supervisor only | User management |\n| Audit Log | Supervisor only | HIPAA compliance and audit trail |\n| Reports | Supervisor only | Data export and analysis |\n| Chat | All users | Team communication |\n| Calendar | All users | Deadline tracking |\n| Settings | All users | Personal account settings |\n\n### Key Dates\n\n| Date | Action |\n|---|---|\n| 15th of month | SPM deadline \u2014 all planners must have submitted |\n| 16th of month | Review compliance reports, follow up with TMs |\n| 1st of month | Review prior month summary, plan current month |\n| Ongoing | Monitor Audit Log for unusual activity |\n\n### Common Issues & Solutions\n\n| Problem | Solution |\n|---|---|\n| User can't log in | Send password reset from Admin Panel |\n| Client in wrong team | Edit client profile, change assigned planner |\n| Missing SPMs in report | Check that submissions were finalized (not just saved as draft) |\n| User's role shows incorrectly | Update role in Admin Panel; user should refresh browser |\n| Audit log not showing recent actions | Actions can take a few minutes to appear; refresh the page |\n| CSV export is empty | Check that your date range and filters include the expected data |\n\n### HIPAA Reminders\n\n- Review the Audit Log **monthly** for unusual access patterns.\n- **Deactivate** accounts promptly when staff leave.\n- Conduct **annual access reviews** \u2014 ensure all active users still need their level of access.\n- Document any suspected HIPAA incidents per BLH's incident response policy.\n- Audit log exports are considered **PHI** \u2014 handle them accordingly.\n\n### Getting Help\n\n1. **BLH Bot** \u2014 first stop for feature questions and policy lookups\n2. **Chat** \u2014 message a colleague or BLH IT support\n3. **System Administrator** \u2014 for infrastructure-level issues\n4. **BLH Compliance Officer** \u2014 for HIPAA-specific guidance\n\n---\n\n*CaseSync is built for Beatrice Loving Heart (BLH).*\n*Guide version: 2025 | Role: Supervisor*\n",
  'video-script': "# CaseSync Training Video Script\n**Beatrice Loving Heart (BLH) \u2014 CaseSync Portal**\n*Estimated runtime: ~11 minutes*\n\n---\n\n## 1. Intro [0:00 \u2013 0:30]\n\n**[VISUAL CUE]** BLH logo fades in on a clean background, then transitions to the CaseSync login screen. Upbeat background music plays softly.\n\n**[NARRATION]**\n\"Welcome to CaseSync \u2014 the case management portal for Beatrice Loving Heart. CaseSync is your central hub for managing clients, tracking deadlines, collaborating with your team, and staying on top of compliance. Whether you're a Supports Planner, Team Manager, or Supervisor, this video will walk you through everything you need to know. Let's get started.\"\n\n---\n\n## 2. Login & Onboarding [0:30 \u2013 1:30]\n\n**[VISUAL CUE]** Screen shows the CaseSync login page at the URL. Cursor highlights the email and password fields. Screen then shows the \"Set your password\" onboarding flow, including the progress indicator.\n\n**[NARRATION]**\n\"To access CaseSync, open your web browser and go to your organization's CaseSync link. Enter the email address your Team Manager or Supervisor used to invite you, then enter your password.\n\nIf this is your first time logging in, you'll receive an invitation email. Click the link in that email \u2014 it will take you directly to a secure setup page where you'll create your password. Choose something strong: at least eight characters, with a mix of letters, numbers, and symbols.\n\nOnce you're logged in, CaseSync may walk you through a brief onboarding checklist \u2014 things like confirming your name, your role, and your contact preferences. Complete these steps and you'll land on your Dashboard.\"\n\n---\n\n## 3. Dashboard Overview [1:30 \u2013 3:30]\n\n**[VISUAL CUE]** Full Dashboard view shown. Camera pans slowly across the screen. Each element gets a brief highlight box as it's mentioned \u2014 greeting, alert banner, week strip, client cards.\n\n**[NARRATION]**\n\"This is your Dashboard \u2014 your home base in CaseSync.\n\nAt the top, you'll see a personalized greeting with your name and role. Right below that is the **Alert Banner**. If any of your clients have overdue tasks, missed monitoring deadlines, or compliance flags, they'll appear here in amber or red. Pay close attention to this section \u2014 it's designed to surface your most urgent priorities at a glance.\n\nJust below the alerts is the **Week Strip** \u2014 a seven-day timeline that shows deadlines falling in the next week. Each deadline is color-coded: red means overdue, amber means due soon, and green means on track. Click any deadline chip to jump straight to that client.\n\nBelow the week strip, you'll see your **Client Cards**. Each card shows the client's name, their current status, and key deadline indicators. Cards with a colored dot in the corner are flagged for attention.\n\nIn the top-right area of the dashboard, you'll find three tools to help you manage your list:\n\n- **Search** \u2014 type any part of a client's name to filter instantly\n- **Filters** \u2014 narrow your view by status, deadline type, or compliance flag\n- **Sort** \u2014 arrange clients by name, next deadline, or risk level\n\nUse these tools together to zero in on exactly who needs your attention today.\"\n\n---\n\n## 4. Client Profile [3:30 \u2013 5:30]\n\n**[VISUAL CUE]** Click on a client card. The full client profile page opens. Camera highlights each section of the form as it's mentioned. Shows the Edit button being clicked, fields being updated, and Save being pressed.\n\n**[NARRATION]**\n\"Click on any client card to open their full profile.\n\nThe client profile page is divided into several sections. At the top, you'll see the client's name, Medicaid ID, date of birth, and primary phone number. Below that are fields for their address, emergency contact, and preferred communication method.\n\nIn the middle section, you'll find the **Eligibility & Services** panel. This is where you'll see the client's eligibility codes \u2014 the specific Medicaid waiver services they're enrolled in, like Community Living Supports or Respite Care. If you're unsure what a code means, hover over it for a description, or ask BLH Bot.\n\nFurther down is the **Monitoring & Compliance** section. This shows key dates: the last contact log, the last SPM submission, and the next deadline. Dates highlighted in red are overdue.\n\nTo make changes, click the **Edit** button in the top-right corner of the profile. All fields become editable. Use the date pickers to update deadline fields \u2014 just click the calendar icon and select the date. When you're done, click **Save** to commit your changes. You'll see a confirmation message at the bottom of the screen.\n\nAt the top of the profile, you may also see a yellow **Alert Banner** for this specific client. This could be a compliance warning, an upcoming service authorization expiration, or a note from your Team Manager.\n\nFinally, look for the **AI Summary** button \u2014 it's labeled 'Generate Summary' or shows a sparkle icon. Click it to have our AI assistant, BLH Bot, generate a concise summary of the client's current status, recent activity, and any outstanding items. This is especially useful before a visit or team meeting.\"\n\n---\n\n## 5. BLH Bot [5:30 \u2013 6:30]\n\n**[VISUAL CUE]** The purple floating action button (FAB) in the bottom-right corner pulses. Click it. The BLH Bot chat panel slides open. Show typing a question and getting a response.\n\n**[NARRATION]**\n\"Meet BLH Bot \u2014 your AI assistant, available anytime you need help.\n\nLook for the purple button in the bottom-right corner of your screen. Click it to open the BLH Bot chat panel. You can ask it anything related to your work in CaseSync.\n\nFor example, you might ask: 'What's due this week for my clients?' \u2014 and BLH Bot will summarize your upcoming deadlines. Or try: 'How do I log a home visit?' \u2014 and it will walk you through the steps. You can even ask: 'What does eligibility code CLS mean?' \u2014 and it will explain it in plain language.\n\nBLH Bot remembers the context of your conversation, so you can follow up with questions like 'Can you tell me more about that?' without repeating yourself.\n\nBLH Bot is not a replacement for clinical judgment or official BLH policy \u2014 but it's a great first stop when you have a quick question or need a refresher. Your Team Manager and Supervisor are always available for escalated questions.\"\n\n---\n\n## 6. Calendar [6:30 \u2013 7:30]\n\n**[VISUAL CUE]** Navigate to the Calendar page via the top navigation. Show the Month view, then click Week, then Day. Show deadlines appearing as colored chips on the calendar.\n\n**[NARRATION]**\n\"The Calendar gives you a visual overview of all your deadlines and important dates in one place.\n\nUse the navigation tabs to switch between **Day**, **Week**, and **Month** views. The Month view is great for planning ahead \u2014 you can see at a glance which days have heavy deadline loads. The Week view gives you a day-by-day breakdown, and the Day view zooms into a single day's schedule.\n\nDeadline chips on the calendar are color-coded by urgency. Click any chip to see details about that deadline and jump directly to the related client profile.\n\nUse the calendar to plan your work: identify clusters of deadlines, avoid surprises at the end of the month, and make sure your Monthly Monitoring submissions \u2014 due by the 15th \u2014 are tracked and visible.\"\n\n---\n\n## 7. Chat [7:30 \u2013 8:30]\n\n**[VISUAL CUE]** Navigate to the Chat page. Show the left sidebar with DMs and channels. Click on a Team Manager name for a DM. Then click on a team channel. Then show a client thread.\n\n**[NARRATION]**\n\"CaseSync includes a built-in messaging system so you can communicate with your team without leaving the portal.\n\nThe Chat page is divided into three areas:\n\n**Direct Messages** \u2014 private one-on-one conversations with specific teammates. Click your Team Manager's name to send them a direct message. All conversations are private and secure.\n\n**Team Channels** \u2014 group conversations for your whole team or specific groups. Use these to share updates, ask questions, or coordinate on shared priorities. Your Team Manager may post important announcements here.\n\n**Client Threads** \u2014 you can have focused conversations attached to a specific client. This keeps client-related discussions organized and easy to find later.\n\nAll Chat messages are stored securely within CaseSync. Avoid sharing sensitive client information in chat \u2014 use the client profile and documents for official records.\"\n\n---\n\n## 8. Documents [8:30 \u2013 9:00]\n\n**[VISUAL CUE]** Open a client profile. Scroll to the Documents section. Show the Upload button, a file browser dialog, and a successfully uploaded file appearing in the list.\n\n**[NARRATION]**\n\"The Documents section in each client profile lets you upload and access important files \u2014 assessments, service plans, authorizations, and more.\n\nTo upload a document, open the client's profile and scroll to the Documents section. Click **Upload**, choose the file from your computer, and confirm. The file will be securely stored in SharePoint and linked to that client's record. You and your team can access uploaded documents anytime from the client profile.\n\nKeep your document naming consistent \u2014 for example: 'ClientLastName_SPM_2025-03.pdf' \u2014 so files are easy to find.\"\n\n---\n\n## 9. Supervisor & Team Manager Features [9:00 \u2013 10:00]\n\n**[VISUAL CUE]** Show the Team page (for Team Managers) and Supervisor dashboard (for Supervisors). Highlight the charts, heatmap, and Admin panel.\n\n**[NARRATION]**\n\"If you're a Team Manager or Supervisor, you have access to additional tools for managing your team.\n\n**Team Managers** can view a Team Dashboard showing compliance stats for each of their Supports Planners \u2014 how many clients each planner manages, how many deadlines are overdue, and overall compliance rates. You can assign clients to specific planners directly from this view, and monitor who may need extra support.\n\n**Supervisors** have access to the full **Supervisor Dashboard**, which includes organization-wide charts, a compliance heatmap, and risk scores across all clients. You can drill down by team, by region, or by individual planner.\n\nSupervisors also have access to the **Admin Panel** \u2014 where you can invite new users, change roles, reset passwords, and manage team assignments. The **Audit Log** records every significant action taken in the system, which supports HIPAA compliance and accountability. You can export reports as CSV files for external review or reporting to state agencies.\"\n\n---\n\n## 10. Notifications [10:00 \u2013 10:30]\n\n**[VISUAL CUE]** Highlight the bell icon in the header. Show the notification dropdown opening, listing several alert types with colored icons.\n\n**[NARRATION]**\n\"The notification bell in the top-right corner of the header keeps you informed of important events.\n\nClick the bell to see your recent notifications. Types include:\n- **Deadline reminders** \u2014 when a client deadline is approaching or overdue\n- **Compliance alerts** \u2014 when a Monthly Monitoring report is due or missed\n- **Team messages** \u2014 when your Team Manager posts in a channel you follow\n- **System updates** \u2014 occasional notices about new features or scheduled maintenance\n\nUnread notifications are shown with a red badge on the bell icon. Stay on top of your notifications \u2014 they're your early warning system.\"\n\n---\n\n## 11. Mobile App [10:30 \u2013 11:00]\n\n**[VISUAL CUE]** Show CaseSync open in a mobile browser (iPhone or Android). Show the \"Add to Home Screen\" prompt. Show the icon appearing on the home screen. Then show the portal running as a full-screen app.\n\n**[NARRATION]**\n\"CaseSync works on your phone as a Progressive Web App \u2014 which means you can install it on your home screen just like a native app, with no app store required.\n\nOn iPhone, open CaseSync in Safari, tap the Share button at the bottom of the screen, and select 'Add to Home Screen.' On Android, open CaseSync in Chrome, tap the three-dot menu, and select 'Add to Home Screen' or 'Install App.'\n\nOnce installed, CaseSync will appear as an icon on your home screen and launch in full-screen mode \u2014 no browser chrome, no distractions. The mobile layout is fully optimized, with a bottom navigation bar for easy one-thumb access to your Dashboard, Chat, Calendar, and more.\"\n\n---\n\n## 12. Outro [11:00 \u2013 11:30]\n\n**[VISUAL CUE]** Return to the Dashboard view. BLH logo fades in. Contact information or help resources briefly appear on screen.\n\n**[NARRATION]**\n\"That's everything you need to get started with CaseSync. You now know how to navigate your Dashboard, manage client profiles, log contacts, submit Monthly Monitoring, use the Calendar, communicate with your team through Chat, and access documents.\n\nIf you ever have a question, your first stop is **BLH Bot** \u2014 just click the purple button and ask. For anything that needs a human answer, reach out to your **Team Manager** or **Supervisor** through the Chat feature.\n\nWelcome to the team, and welcome to CaseSync. Let's do great work together for the people we serve.\"\n\n---\n\n*End of script. Total estimated runtime: ~11 minutes.*\n*Produced for Beatrice Loving Heart (BLH) \u2014 CaseSync Portal Onboarding*\n",
}

export async function GET(req: NextRequest) {
  const guide = req.nextUrl.searchParams.get('guide')
  if (!guide || !GUIDES[guide]) {
    return NextResponse.json({ error: 'Guide not found' }, { status: 404 })
  }
  const md = ensureFreshTableOfContents(GUIDES[guide])
  return new NextResponse(md, {
    headers: { 'Content-Type': 'text/plain' }
  })
}
